#include <iostream>
#include <string>

using namespace std;

bool isPalindrome(string s)
{
    int left = 0;
    int right = s.length() - 1;

    while (left < right)
    {
        if (s[left] != s[right])
        {
            return false;
        }
        left++;
        right--;
    }
    return true;
}

int main()
{
    cout << isPalindrome("racecar") << endl;
    cout << isPalindrome("hello") << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <unordered_map>

using namespace std;

bool isAnagram(string a, string b)
{
    if (a.length() != b.length())
    {
        return false;
    }

    unordered_map<char, int> freq;

    for (char c : a)
    {
        freq[c]++; // count characters in a
    }
    for (char c : b)
    {
        freq[c]--; // subtract characters in b
    }

    for (auto entry : freq)
    {
        if (entry.second != 0)
        {
            return false; // counts don't cancel out — not an anagram
        }
    }
    return true;
}

int main()
{
    cout << isAnagram("listen", "silent") << endl;
    cout << isAnagram("hello", "world") << endl;

    return 0;
}

