#include <iostream>
#include <vector>

using namespace std;

void reverseString(vector<char> &s)
{
    vector<char> reversed(s.size());

    for (int i = 0; i < s.size(); i++)
    {
        reversed[i] = s[s.size() - 1 - i];
    }

    s = reversed;
}

int main()
{
    vector<char> s = {'h', 'e', 'l', 'l', 'o'};

    reverseString(s);
    for (char c : s) cout << c;

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

void reverseString(vector<char> &s)
{
    int left = 0, right = s.size() - 1;

    while (left < right)
    {
        swap(s[left], s[right]);
        left++;
        right--;
    }
}

int main()
{
    vector<char> s = {'h', 'e', 'l', 'l', 'o'};

    reverseString(s);
    for (char c : s) cout << c;

    return 0;
}

